import {SpotterMainApp} from "./type";
import {boostrapNetworkSystem, NetworkSystemOptions} from "./network";
import {boostrapLogSystem, LogSystemOptions} from "./logger";
import {boostrapI18nSystem, I18nSystemOptions} from "./i18n";
import { boostrapMicroAppSystem, MicroAppSystemOptions} from "./app";
import {boostrapRouterSystem, RouterSystemOptions} from "./router";


interface CreateSpotterMainAppOptions {
    log: LogSystemOptions
    network: NetworkSystemOptions
    i18n: I18nSystemOptions
    microApp: MicroAppSystemOptions
    router: RouterSystemOptions
}

const sptApp = {} as SpotterMainApp


export function createSpotterMainApp(options: CreateSpotterMainAppOptions){
    /**
     * 初始化日志模块
     */
    boostrapLogSystem(options.log, sptApp)
    /**
     * 初始化国际化模块
     */
    boostrapI18nSystem(options.i18n, sptApp)
    /**
     * 初始化网络模块
     */
    boostrapNetworkSystem(options.network, sptApp)
    /**
     * 初始化微应用模块
     */
    boostrapMicroAppSystem(options.microApp, sptApp)

    /**
     * 初始化路由模块
     */
    boostrapRouterSystem(options.router, sptApp)

    return sptApp
}

export type SptAppScope = keyof SpotterMainApp;

export function getSptApp(): SpotterMainApp;
export function getSptApp<T extends SptAppScope>(scope?: T): SpotterMainApp[T];
export function getSptApp (scope?: SptAppScope){
    if (scope) {
        if (!sptApp[scope]) {
            throw new Error(`sptApp have no property that named: ${scope}`);
        } else {
            return sptApp[scope];
        }
    }
    return sptApp;
}
